      spx_30d_return = (SPX_Close / lag(SPX_Close, 30)) - 1,
      btc_30d_return = (BITCOIN_Close / lag(BITCOIN_Close, 30)) - 1
    )
  assign("merged_data", merged_data, envir = .GlobalEnv)
})

